import{_ as t,c as o,o as s,ag as e}from"./chunks/framework.DVUBUV_u.js";const d=JSON.parse('{"title":"Инспектор","description":"","frontmatter":{"title":"Инспектор"},"headers":[],"relativePath":"props/inspect.md","filePath":"props/inspect.md"}'),a={name:"props/inspect.md"};function n(p,r,l,i,c,g){return s(),o("div",null,[...r[0]||(r[0]=[e('<h1 id="режим-inspect-выбор-компонента-на-странице" tabindex="-1">Режим Inspect (выбор компонента на странице) <a class="header-anchor" href="#режим-inspect-выбор-компонента-на-странице" aria-label="Permalink to &quot;Режим Inspect (выбор компонента на странице)&quot;">​</a></h1><p>Режим <strong>Inspect</strong> на вкладке <strong>Props</strong> позволяет выбрать интересующий фрагмент интерфейса <strong>непосредственно на странице</strong> и после клика сузить список компонентов до поддерева, связанного с выбранным узлом. По смыслу это близко к выбору элемента в инструментах разработчика браузера, однако результатом здесь становится <strong>фильтрация таблицы Props</strong>, а не переход к DOM-структуре.</p><p>Общее описание вкладки Props см. в разделе <a href="/docs/props/general.html">Основные возможности</a>.</p><hr><h2 id="запуск-и-остановка" tabindex="-1">Запуск и остановка <a class="header-anchor" href="#запуск-и-остановка" aria-label="Permalink to &quot;Запуск и остановка&quot;">​</a></h2><p>Кнопка <strong>Inspect</strong> находится на панели инструментов вкладки <strong>Props</strong> (иконка указателя) и включает режим выбора элемента на странице для фильтрации списка компонентов.</p><p>Перед активацией режима список компонентов автоматически <strong>обновляется</strong>, чтобы структура дерева и данные соответствовали текущему состоянию страницы.</p><p>По умолчанию при включении <strong>Inspect Mode</strong> интерфейс инспектора в режиме <strong>overlay</strong> временно скрывается, чтобы не перекрывать элементы страницы. Это поведение можно изменить в настройках <strong>Options → Inspect Mode → Hide overlay while inspecting</strong>.</p><p>Повторное нажатие <strong>Inspect</strong> отключает режим выбора, не сбрасывая уже применённый фильтр.</p><p>Клавиша <strong>Escape</strong> отменяет текущий режим инспекции без выбора элемента.</p><p>При переключении вкладки инспектора или закрытии панели режим выбора автоматически сбрасывается.</p><hr><h2 id="поведение-на-странице" tabindex="-1">Поведение на странице <a class="header-anchor" href="#поведение-на-странице" aria-label="Permalink to &quot;Поведение на странице&quot;">​</a></h2><p>После включения Inspect поверх страницы активируется режим <strong>захвата указателя</strong>: движение мыши и выбор элемента обрабатываются независимо от обычного поведения страницы, включая элементы, которые в обычном режиме не принимают пользовательские клики.</p><p>Выбор привязывается не к произвольному DOM-узлу, а к ближайшему элементу, связанному с <strong>инстансом Vue</strong>.</p><p>Пока курсор находится над страницей, элемент под ним <strong>подсвечивается</strong>, рядом может отображаться <strong>всплывающая подсказка</strong> с краткой информацией:</p><ul><li>имя компонента;</li><li>описание корневого DOM-элемента (тег, часть класса или <code>id</code>);</li><li>количество props;</li><li>число дочерних связанных элементов.</li></ul><p>Тема подсказки (светлая или тёмная) соответствует текущим настройкам инспектора.</p><p>Элементы интерфейса <strong>Vue Inspector</strong> (overlay, шеврон, вспомогательные панели режима Inspect) исключаются из области выбора и не участвуют в определении компонента.</p><p>Если в настройках включено скрытие overlay во время инспекции, после завершения выбора или отмены режима интерфейс возвращается в исходное состояние.</p><hr><h2 id="результат-выбора" tabindex="-1">Результат выбора <a class="header-anchor" href="#результат-выбора" aria-label="Permalink to &quot;Результат выбора&quot;">​</a></h2><p>После выбора элемента на странице:</p><ul><li>режим Inspect завершается;</li><li>в таблице Props остаются компоненты, относящиеся к выбранному <strong>корню</strong>;</li><li>в верхней панели появляется индикатор <strong>Filtered</strong>, показывающий, что список ограничен выбранным поддеревом.</li></ul><p>Нажатие на <strong>Filtered</strong> снимает ограничение и возвращает полный список компонентов после обновления данных.</p><p>Повторный запуск Inspect при уже активном фильтре позволяет выбрать другой корневой элемент и заменить текущую область фильтрации.</p><hr><h2 id="ограничения-и-типичные-ситуации" tabindex="-1">Ограничения и типичные ситуации <a class="header-anchor" href="#ограничения-и-типичные-ситуации" aria-label="Permalink to &quot;Ограничения и типичные ситуации&quot;">​</a></h2><ul><li>Если под курсором отсутствует связанный Vue-элемент, выбор не приведёт к фильтрации списка.</li><li>При сложной вложенности DOM результат может соответствовать ближайшему связанному компоненту, а не визуально ожидаемому уровню.</li><li>Режим Inspect влияет только на состав списка компонентов; <strong>избранное</strong>, <strong>чёрный список</strong> и <strong>поиск</strong> продолжают применяться поверх текущего фильтра.</li></ul><p>Подробности см. в разделах <a href="/docs/props/favorite.html">Избранное</a> и <a href="/docs/props/blacklist.html">Чёрный список</a>.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/props/general.html">Основные возможности Props</a></li><li><a href="/docs/props/favorite.html">Избранное</a></li><li><a href="/docs/props/blacklist.html">Чёрный список</a></li></ul>',33)])])}const u=t(a,[["render",n]]);export{d as __pageData,u as default};
